const items = $input.all();
const flat = [];

for (const item of items) {
  const notionPageId = item.json.id;
  const props = item.json;

  const titel     = props.property_titel || props.name || 'Kein Titel';
  const kurztext  = props.property_kurztext || '';
  const katRaw    = props.property_kategorie;
  const kategorie = Array.isArray(katRaw) ? katRaw.join(', ') : (katRaw || '');
  const verAm     = props.property_ver_ffentlicht_am
    || props.property_veroffentlicht_am
    || props.property_veroeffentlicht_am;
  const datum          = verAm?.start || new Date().toISOString().split('T')[0];
  const currentBlogIDs = props.property_confluence_blog_i_ds
    || props.property_confluenceblogids
    || props.property_confluence_blog_ids
    || '';

  const typ = props.property_typ || 'Individuell';

  const dbKunden   = props.property_db_kunden || [];
  const kundenIds  = Array.isArray(dbKunden) ? dbKunden : [dbKunden];

  const dbGruppen  = props.property_db_gruppen || [];
  const gruppenIds = Array.isArray(dbGruppen) ? dbGruppen : [dbGruppen];

  if ((typ === 'Gruppe' || typ === 'Beides') && gruppenIds.filter(Boolean).length === 0) {
    flat.push({
      json: {
        _guard_error: true,
        _error_reason: `Typ="${typ}" aber DB_Gruppen ist leer`,
        notionPageId,
        titel
      }
    });
    continue;
  }
  if ((typ === 'Individuell' || typ === 'Beides') && kundenIds.filter(Boolean).length === 0) {
    flat.push({
      json: {
        _guard_error: true,
        _error_reason: `Typ="${typ}" aber DB_Kunden ist leer`,
        notionPageId,
        titel
      }
    });
    continue;
  }

  if (typ === 'Individuell' || typ === 'Beides') {
    for (const kundePageId of kundenIds) {
      if (!kundePageId) continue;
      flat.push({
        json: {
          notionPageId,
          titel,
          kurztext,
          kategorie,
          datum,
          currentBlogIDs,
          empfaengerPageId: kundePageId,
          empfaengerTyp: 'individuell',
          _guard_error: false
        }
      });
    }
  }

  if (typ === 'Gruppe' || typ === 'Beides') {
    for (const gruppePageId of gruppenIds) {
      if (!gruppePageId) continue;
      flat.push({
        json: {
          notionPageId,
          titel,
          kurztext,
          kategorie,
          datum,
          currentBlogIDs,
          empfaengerPageId: gruppePageId,
          empfaengerTyp: 'gruppe',
          _guard_error: false
        }
      });
    }
  }
}

return flat;

const loopItem  = $('Loop: Ein Paar pro Durchlauf').item.json;
const notionData = $json;

const spaceKey = notionData.property_confluence_space_key || '';

const empfaengerTyp  = loopItem.empfaengerTyp;
const isGruppenSpace = spaceKey.startsWith('GP');
const isKundenSpace  = spaceKey.startsWith('KP');

if (empfaengerTyp === 'gruppe' && !isGruppenSpace) {
  throw new Error(
    `GUARD VERLETZUNG: Typ=Gruppe aber SpaceKey="${spaceKey}" ist kein GP*-Space.` +
    ` Notion-Seite: ${loopItem.notionPageId}`
  );
}
if (empfaengerTyp === 'individuell' && !isKundenSpace) {
  throw new Error(
    `GUARD VERLETZUNG: Typ=Individuell aber SpaceKey="${spaceKey}" ist kein KP*-Space.` +
    ` Notion-Seite: ${loopItem.notionPageId}`
  );
}

return {
  json: {
    spaceKey,
    empfaengerTyp,
    notionPageId:   loopItem.notionPageId,
    titel:          loopItem.titel,
    kurztext:       loopItem.kurztext,
    kategorie:      loopItem.kategorie,
    datum:          loopItem.datum,
    currentBlogIDs: loopItem.currentBlogIDs
  }
};

parameters.body:
={{ (() => {
  const d = $('Daten zusammenfuehren').item.json;
  const escHtml = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  const titel     = escHtml(d.titel);
  const kurztext  = escHtml(d.kurztext);
  const kategorie = escHtml(d.kategorie);
  const datum     = escHtml(d.datum);
  const bodyHtml  = `<h2>${titel}</h2><p>${kurztext}</p>`
    + (kategorie ? `<p><em>Kategorie: ${kategorie}</em></p>` : '')
    + `<p><em>Veroeffentlicht am: ${datum}</em></p>`;
  return JSON.stringify({
    type: 'blogpost',
    title: `${d.titel} – ${d.datum}`,
    space: { key: d.spaceKey },
    metadata: {
      labels: [{ prefix: 'global', name: 'aktuelle-info' }]
    },
    body: {
      storage: {
        value: bodyHtml,
        representation: 'storage'
      }
    }
  });
})() }}

