// Neue Blog-ID aus Confluence-Antwort
const newBlogId  = $json.id || '';
const prev       = $('Daten zusammenfuehren').item.json;
const spaceKey   = prev.spaceKey || '';
const notionPageId = prev.notionPageId || '';
const datum      = prev.datum || '';

// Bestehende Blog-IDs um neuen Eintrag ergaenzen
// Format: "KPA:12345,KPB:67890"
const current    = prev.currentBlogIDs || '';
const newEntry   = `${spaceKey}:${newBlogId}`;
const updatedBlogIDs = current
  ? `${current},${newEntry}`
  : newEntry;

return {
  json: {
    notionPageId,
    updatedBlogIDs,
    datum
  }
};

const items = $input.all();

const errors = items.filter(i => i.json._guard_error === true);

if (errors.length > 0) {
  const errorDetails = errors.map(e =>
    `• "${e.json.titel}" (${e.json.notionPageId}): ${e.json._error_reason}`
  ).join('\n');

  return errors.map(e => ({
    json: {
      _guard_triggered: true,
      notionPageId: e.json.notionPageId,
      titel: e.json.titel,
      errorReason: e.json._error_reason,
      errorSummary: errorDetails,
      timestamp: new Date().toISOString()
    }
  }));
}

return items.filter(i => !i.json._guard_error);
